#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <cuda_runtime.h>

// ============================================================================
// 2D thread tiling GEMM（外积视角）
//   block 计算 BM x BN 的 C tile
//   每个 thread 计算 TM x TN 个 C 元素
//   threads/block = (BM/TM) * (BN/TN)
// ============================================================================
constexpr int BM = 64;
constexpr int BN = 64;
constexpr int BK = 8;
constexpr int TM = 4;
constexpr int TN = 4;

constexpr int THREADS = (BM / TM) * (BN / TN);   // 16*16 = 256

// C = A(MxK) * B(KxN)，全部 row-major
__global__ void gemm_2d_thread_tiling(const float* a, const float* b,
        float* c, int M, int N, int K) {
    // 本 block 负责的 C tile 左上角
    const int blockRow = blockIdx.y * BM;   // C 的行起点
    const int blockCol = blockIdx.x * BN;   // C 的列起点

    // 本 thread 在 (BM/TM) x (BN/TN) 的线程网格里的位置
    const int threadRow = threadIdx.x / (BN / TN);   // 0..15
    const int threadCol = threadIdx.x % (BN / TN);   // 0..15

    __shared__ float As[BM][BK];
    __shared__ float Bs[BK][BN];

    // 每个 thread 负责的 TM x TN 累加器
    float acc[TM][TN] = {0.0f};
    // 外积用的寄存器：A 的一小列 / B 的一小行
    float regM[TM];
    float regN[TN];

    // ---- 加载索引：256 个线程协作搬运 As(64x8) 和 Bs(8x64) ----
    // As: BM*BK = 512 个元素，每线程搬 512/256 = 2 个
    const int innerRowA = threadIdx.x / BK;          // 0..31
    const int innerColA = threadIdx.x % BK;          // 0..7
    const int strideA   = THREADS / BK;              // 32（每轮覆盖 32 行）
    // Bs: BK*BN = 512 个元素，每线程搬 2 个
    const int innerRowB = threadIdx.x / BN;          // 0..3
    const int innerColB = threadIdx.x % BN;          // 0..63
    const int strideB   = THREADS / BN;              // 4（每轮覆盖 4 行）

    // ---- 沿 K 方向，每次处理 BK 列 ----
    for (int k0 = 0; k0 < K; k0 += BK) {
        // 1) 加载 A tile 到 As：全局 A[blockRow + r][k0 + innerColA]
        for (int off = 0; off < BM; off += strideA) {
            int gRow = blockRow + innerRowA + off;
            int gCol = k0 + innerColA;
            As[innerRowA + off][innerColA] =
                (gRow < M && gCol < K) ? a[gRow * K + gCol] : 0.0f;
        }
        // 2) 加载 B tile 到 Bs：全局 B[k0 + innerRowB][blockCol + innerColB]
        for (int off = 0; off < BK; off += strideB) {
            int gRow = k0 + innerRowB + off;
            int gCol = blockCol + innerColB;
            Bs[innerRowB + off][innerColB] =
                (gRow < K && gCol < N) ? b[gRow * N + gCol] : 0.0f;
        }
        __syncthreads();

        // 3) 计算：对这 BK 列做外积累加
        //    提示：
        //      for (int k = 0; k < BK; k++) {
        //          // (a) 把 As 的一小列读进 regM[0..TM-1]
        //          //     regM[i] = As[threadRow*TM + i][k];
        //          // (b) 把 Bs 的一小行读进 regN[0..TN-1]
        //          //     regN[j] = Bs[k][threadCol*TN + j];
        //          // (c) 外积累加
        //          //     acc[i][j] += regM[i] * regN[j];
        //      }
        // TODO: 在这里手写 (a)(b)(c)

        __syncthreads();
    }

    // ---- 写回：每个 thread 写自己的 TM x TN 小块 ----
    for (int i = 0; i < TM; i++) {
        for (int j = 0; j < TN; j++) {
            int gRow = blockRow + threadRow * TM + i;
            int gCol = blockCol + threadCol * TN + j;
            if (gRow < M && gCol < N) {
                c[gRow * N + gCol] = acc[i][j];
            }
        }
    }
}

void gemm_2d_thread_tiling_launcher(const float* a, const float* b,
        float* c, int M, int N, int K) {
    dim3 block(THREADS);
    dim3 grid((N + BN - 1) / BN, (M + BM - 1) / BM);

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);
    gemm_2d_thread_tiling<<<grid, block>>>(a, b, c, M, N, K);
    cudaEventRecord(stop);

    cudaEventSynchronize(stop);
    float tm = 0;
    cudaEventElapsedTime(&tm, start, stop);

    double gflops = 2.0 * M * N * K / (tm / 1e3) / 1e9;
    printf("gemm_2d_thread_tiling cost: %.3f ms, %.2f GFLOPS\n", tm, gflops);

    cudaEventDestroy(start);
    cudaEventDestroy(stop);
}

// CPU 参考实现
static void gemm_cpu_ref(const float* a, const float* b, float* c,
        int M, int N, int K) {
    for (int row = 0; row < M; row++) {
        for (int col = 0; col < N; col++) {
            float sum = 0.0f;
            for (int k = 0; k < K; k++) {
                sum += a[row * K + k] * b[k * N + col];
            }
            c[row * N + col] = sum;
        }
    }
}

#define CUDA_CHECK(call)                                                   \
    do {                                                                   \
        cudaError_t err = (call);                                          \
        if (err != cudaSuccess) {                                          \
            printf("CUDA error %s at %s:%d\n", cudaGetErrorString(err),    \
                   __FILE__, __LINE__);                                    \
            exit(EXIT_FAILURE);                                            \
        }                                                                  \
    } while (0)

